import React from "react";
import { useNavigate } from "react-router-dom";

const Layout = ({ children, title }) => {
  const navigate = useNavigate();

  const logout = () => {
    localStorage.removeItem("token");
    localStorage.removeItem("user");
    navigate("/login");
  };

  return (
    <div style={styles.wrapper}>

      {/* SIDEBAR */}
      <div style={styles.sidebar}>
        <h2 style={styles.logo}>DailyWorker</h2>

        <button style={styles.btn} onClick={() => navigate("/")}>
          Dashboard
        </button>

        <button style={styles.logout} onClick={logout}>
          Logout
        </button>
      </div>

      {/* MAIN AREA */}
      <div style={styles.main}>

        {/* TOP BAR */}
        <div style={styles.topbar}>
          <h3>{title}</h3>
        </div>

        {/* CONTENT */}
        <div style={styles.content}>
          {children}
        </div>

      </div>

    </div>
  );
};

export default Layout;

/* ---------------- STYLES ---------------- */

const styles = {
  wrapper: {
    display: "flex",
    height: "100vh",
    fontFamily: "Segoe UI",
    background: "#f5f6f8"
  },

  sidebar: {
    width: "240px",
    background: "#111827",
    color: "white",
    padding: "20px",
    display: "flex",
    flexDirection: "column"
  },

  logo: {
    marginBottom: "20px"
  },

  btn: {
    padding: "10px",
    marginBottom: "10px",
    background: "transparent",
    border: "1px solid #374151",
    color: "white",
    borderRadius: "6px",
    cursor: "pointer"
  },

  logout: {
    marginTop: "auto",
    padding: "10px",
    background: "red",
    color: "white",
    border: "none",
    borderRadius: "6px",
    cursor: "pointer"
  },

  main: {
    flex: 1,
    display: "flex",
    flexDirection: "column"
  },

  topbar: {
    background: "white",
    padding: "15px",
    borderBottom: "1px solid #e5e7eb"
  },

  content: {
    padding: "20px"
  }
};
